#include <bits/stdc++.h>
using namespace std;
#define ull unsigned long long
ull n,m,c,k;
int main()
{
//	freopen("zoo3.in","r",stdin);
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>c>>k;
	ull flag=0,ans=1,tmp=0;
	for(int i=1;i<=n;i++)
	{
		ull x;
		cin>>x;
		flag|=x;
	}
//	cout<<flag<<"\n";
	while(m--)
	{
		ull x;
		cin>>x;
//		cout<<x<<" ";
		if((flag&(1ull<<x))==0) tmp|=(1ull<<x);
		cin>>x;
	}
//	cout<<tmp<<"\n";
	for(int i=0;i<k;i++) 
	{
		if((tmp&(1ull<<i))==0) ans=ans<<1;
	}
	if(ans==0&&n==0) cout<<"18446744073709551616";
	else cout<<ans-n;
	return 0;
}
